const workflow = $json.workflow || {};
const execution = $json.execution || {};
const error = execution.error || {};

const errorDetails = {
  workflow_name: workflow.name || 'Unknown',
  workflow_id: workflow.id || 'Unknown',
  last_node: execution.lastNodeExecuted || 'Unknown',
  error_message: error.message || 'No error message',
  execution_id: execution.id || 'Unknown',
  timestamp: new Date().toISOString()
};

// Discord message for #echoes
const discordMessage = [
  '**Aerys Error**',
  `Workflow: ${errorDetails.workflow_name}`,
  `Node: ${errorDetails.last_node}`,
  `Error: ${errorDetails.error_message}`,
  `Exec: ${errorDetails.execution_id}`,
].join('\n');

return [{json: {
  ...errorDetails,
  discord_message: discordMessage,
  echoes_channel_id: 'YOUR_ERROR_CHANNEL_ID', // #echoes — hardcoded, no $vars
  audit_details: JSON.stringify({
    workflow_name: errorDetails.workflow_name,
    workflow_id: errorDetails.workflow_id,
    last_node: errorDetails.last_node,
    error_message: errorDetails.error_message,
    execution_id: errorDetails.execution_id,
    timestamp: errorDetails.timestamp
  })
}}];
